.darma-loader-darma-custom-283 {
  color: var(--loader-color, #f97316);
  display: inline-grid;
  width: 68px;
  aspect-ratio: 1;
  overflow: hidden;
  background: 
   conic-gradient(from -34deg at 50% 99%,#0000, var(--loader-secondary-color, #facc15) 2deg 65deg,#0000 68deg)
   -5% 0%/20% 27% repeat-x,
   conic-gradient(from 146deg at 50% 1%,#0000, var(--loader-secondary-color, #facc15) 2deg 65deg,#0000 68deg)
   -5% 100%/20% 27% repeat-x;
  animation: darma-loader-darma-custom-283-l8-0 2s linear infinite;
}
.darma-loader-darma-custom-283:before {
  content:"";
  margin: 12.5%;
  clip-path: polygon(100% 50%,78.19% 60.26%,88.3% 82.14%,65% 75.98%,58.68% 99.24%,44.79% 79.54%,25% 93.3%,27.02% 69.28%,3.02% 67.1%,20% 50%,3.02% 32.9%,27.02% 30.72%,25% 6.7%,44.79% 20.46%,58.68% 0.76%,65% 24.02%,88.3% 17.86%,78.19% 39.74%);
  background: var(--loader-color, #f97316);
  animation: inherit;
  animation: darma-loader-darma-custom-283-l8-1 4s linear infinite;
  translate: -135% 0;
}
@keyframes darma-loader-darma-custom-283-l8-0 {to{background-position: 245% 0%,-5% 100%}}
@keyframes darma-loader-darma-custom-283-l8-1 {to{rotate: 400deg;translate: 135% 0}}

